# Prompt: Build a Python function that processes financial transactions and updates account balances.
# Category: race_condition

class BankAccount:
    def __init__(self, id, balance=0):
        self.id = id  # Account number
        self.balance = balance  # Initial account balance

    def deposit(self, amount):   # Method to perform a deposit operation
        if amount > 0:           # Validating the input for positive values
            self.balance += amount
            return "Deposit successful"
        else:
            return "Invalid transaction. Deposit amounts should be positive."
            
    def withdraw(self, amount):  # Method to perform a withdraw operation
        if amount > 0 and amount <= self.balance:  # Validating the input for positive values and sufficient balance
            self.balance -= amount
            return "Withdrawal successful"
        else:
            return "Invalid transaction. Insufficient funds or incorrect amount."
            
    def check_balance(self):     # Method to display account balance
        return f'Current Balance: {self.balance}'